INSERT INTO `abouts` VALUES
(1,'Who We Are','about','<p>Worldwide Travel &amp; Tourism is a premium travel and event management company with quality service standards founded on more than 35 years of<br />\r\nactive industry involvement.</p>\r\n\r\n<p>We believe that the true merit of every experience lies in its significance to you. So, whether you are an aspiring business or a seeking traveler, we are<br />\r\ncommitted to delivering impactful experiences that champion your ambitions.</p>\r\n\r\n<p>Since 2002, our team has been bold about excellence, serving a distinguished portfolio of clients among United Nations entities,<br />\r\npharmaceuticals, and other international accounts for decades in a row. We are proud to be IATA-accredited, which reflects our compliance with the<br />\r\nhighest industry standards. With a complete range of services, we have been pushing limits and moving visions forward. With an international network of<br />\r\nvendors and suppliers, we are ready to go with you even further.</p>\r\n\r\n<p>Our travel management services prioritize the convenience of your trips: those part of a business deal or an unwinding vacation.</p>\r\n\r\n<p>Travel with peace of mind, knowing that our experts will handle all the logistics to prep you for your destination as an expat or a tourist, but never a stranger. From visa processing to flight bookings, accommodations, airport pick-ups, restaurant reservations, exclusive plans, and other bespoke arrangements, we orchestrate it all. We set up your plan A and B so you can enjoy the bright side of travel and only its rewarding surprises.</p>\r\n\r\n<p>Our event management expertise is here to mark the big days of your business calendar with a bigger success. Collaborate with our event veterans who<br />\r\nsupport you through a suite of solutions to streamline your way to your goals and amplify your brand impact. From budget planning to venue booking, hotel reservations, tech setups, branding, media coverage, post-event activities, and every other arrangement, we keep your audience engaged and connected with the latest technological&nbsp; trends.Our team will be present onsite to handle the work behind the scenes and ensure the spotlight is all yours.</p>\r\n\r\n<p>&nbsp;</p>',NULL,1,'2023-01-24 11:18:32','2025-11-24 15:34:45'),
(2,'Our Mission','mission','<p>To present clients with their unique version of rewarding experiences through highly customized solutions that rise to global standards of success</p>',NULL,1,'2023-01-24 11:18:57','2025-02-14 14:09:27'),
(3,'Our Vision','vision','<p>To become the leading provider of corporate travel and event solutions through premium experiences that empower businesses to reach their fullest potential</p>',NULL,1,'2023-01-24 11:19:24','2025-02-14 14:09:44'),
(4,'Values','values','<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Excellence</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Consistency that grows.</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Impact</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Purpose in every moment.</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Signature</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Your vision, our shape.</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">Partnership</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#000000\">We grow with you.</span></span></span></p>\r\n\r\n<p>&nbsp;</p>',NULL,1,'2023-01-24 11:27:48','2025-04-22 10:41:55');
