(28,'Formula 1',NULL,NULL,'2024-09-20',0,NULL,'<p>Call out to our Formula 1 fanatics&nbsp;<br />\r\nTickets for Round 23 in Qatar and Round 24 in Abu Dhabi are now available with WorldWide Travel &amp; Tourism!&nbsp;<br />\r\nLimited seats are available, book now for hassle-free travel!<br />\r\n<br />\r\nFor more info on booking and the ticket details contact us on +961 79 119311</p>',1,'2024-09-19 04:16:54','2025-03-12 18:48:44'),
