INSERT INTO `packages` VALUES
(3,'Honeymoon Sri Lanka','Sri Lanka',NULL,'6 Days - 5 Nights',0,NULL,'Honeymoon-Sri-Lanka-86644221383Y572','<p><strong>Hotels</strong></p>\r\n\r\n<p>Hotel Accommodation &ndash; 5 Star</p>\r\n\r\n<p>01 Night at <a href=\"https://www.movenpick.com/en/asia/sri-lanka/colombo/movenpick-hotel-colombo.html?utm_source=google&amp;utm_medium=local&amp;utm_campaign=hotel-MHR-Colombo&amp;y_source=1_MTUzNjI4NzAtNzE1LWxvY2F0aW9uLndlYnNpdGU%3D\">Movenpick</a>, Colombo| Superior Room &ndash; 5*<br />\r\n02 Nights at <a href=\"https://www.barcelo.com/en-ww/occidental-paradise-dambulla/?utm_source=google&amp;utm_medium=organic&amp;utm_campaign=my_business&amp;utm_content=30777\">Occidental Paradise</a>, Dambulla| Deluxe Room &ndash; 5*<br />\r\n01 Nights at <a href=\"https://www.mahaweli.com/\">Mahaweli Reach</a>, Kandy| Deluxe Room &ndash; 5*<br />\r\n01 Nights at <a href=\"https://www.avanihotels.com/en/bentota?utm_source=GoogleMyBusiness&amp;utm_medium=GMB&amp;utm_term=Bentota&amp;utm_content=Home&amp;utm_campaign=Google_GMB\">Avani Bentota</a>, Bentota| Standard Ocean View Room &ndash; 5*</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Tours</strong></p>\r\n\r\n<p>Day 01 &ndash; Airport| Colombo</p>\r\n\r\n<ul>\r\n	<li>Your First Destination is Colombo (Approx. 01 hours),</li>\r\n	<li>Colombo Explore the city and indulge in shopping as well</li>\r\n</ul>\r\n\r\n<p><br />\r\nDay 02 &ndash; Colombo | Dambulla</p>\r\n\r\n<ul>\r\n	<li>Proceed to Dambulla (Approx. 04 &frac12; hours),</li>\r\n	<li>En route Pinnewela Elephant Orphanage, rest of the day at leisure</li>\r\n</ul>\r\n\r\n<p><br />\r\nDay 03 &ndash; Dambulla City Tour</p>\r\n\r\n<ul>\r\n	<li>in the morning climb Sigiriya Lion Rock Fortress (The climb to the top will take about 45-minutes. Exploring the whole area will take you about 2 &ndash; 3 hours), once arrived at the top of rock enjoy the incredible 360 degrees view over the whole area.</li>\r\n	<li>Hiriwaduna Village &ndash; A village tour where you can experience a bullock cart ride, a boat ride across the serene water blanketed with lily pads. Thereafter, escort to a house in the village and enjoy an authentic Sri Lankan meal and then return on a tuk-tuk. Rest of the day at leisure.</li>\r\n	<li>Later in the evening, go on a Jeep safari to Minneriya National Park which is highly famed for its elephants and wildlife. Minneriya hosts more than 160 species of birds, a few of which are endemic to Sri Lanka, such as the Sri Lanka Hanging Parrot, the Sri Lanka Jungle Fowl, and the Sri Lanka Grey Horn-bill etc.</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Day 04 &ndash; Dambulla | Kandy</p>\r\n\r\n<ul>\r\n	<li>Proceed to Kandy (Approx. 02 &frac12; hours), en route make a stopover at a Spice Garden in Matale, it is a Free Thing To Do In Lanka.</li>\r\n	<li>Kandy city tour: You will have some time to do shopping ,lake drive/ walk, visit marketplace. Visit a gem shop and get to know about the precious and semi-precious gemstones found in the Paradise Island. Visit the</li>\r\n	<li>Peradeniya Royal Botanical Garden. Try to walk across the bouncy pedestrian suspension bridge across the river (Mahaweli &ndash; the longest river in Sri Lanka).</li>\r\n	<li>In the evening watch the Kandy Cultural Show. Sri Lanka, a country rich with culture &amp; tradition, offers a vibrant performance of Sri Lankan traditional dances.</li>\r\n</ul>\r\n\r\n<p>Day 05 &ndash; Kandy | Bentota</p>\r\n\r\n<ul>\r\n	<li>Proceed to Bentota (Approx. 4 hours)</li>\r\n	<li>Go on a Boat Safari in Madhu River (01 hour) as you watch for crocodiles or water monitors as they slither beneath the murky surface or as the endemic birds of prey hover over you! Towards the end of your safari, treat yourself to a soothing, natural treatment at the local &lsquo;fish spa&rsquo;. Perch yourself on the deck and pop your feet in for a natural fish treatment as your dead skin cells are cleaned off leaving your feet smooth and clean.</li>\r\n	<li>Thereafter, visit Kosgoda Turtle Hatchery, various species of sea&nbsp;turtles&nbsp;in different stages of their lives can be found here. &nbsp;</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Day 06 &ndash; Bentota | Airport</p>\r\n\r\n<ul>\r\n	<li>(Approx. 45 min), transfer to airport</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Package Includes:</strong></p>\r\n\r\n<ul>\r\n	<li>Per person cost of DBL sharing on the above hotel or similar</li>\r\n	<li>Meal plan on Half Board Basis&nbsp;&nbsp;</li>\r\n	<li>Transfers &amp; Tours by air &ndash; conditioned Car with the services of an&nbsp;English/Arabic speaking chauffeur guide cum driver throughout the tour&nbsp;&nbsp;</li>\r\n	<li>Expressway and parking charges</li>\r\n	<li>Local government taxes and service charges</li>\r\n	<li>Entrance Fees:</li>\r\n</ul>\r\n\r\n<ul>\r\n	<li>Lotus Tower</li>\r\n	<li>Gangarama Temple</li>\r\n	<li>Pinnawala Elephant Orphanage</li>\r\n	<li>Sigiriya Rock</li>\r\n	<li>Hiriwadunna Village Trek</li>\r\n	<li>Minneriya National Park with Jeep Safari</li>\r\n	<li>Spice Garden</li>\r\n	<li>Kandy Temple</li>\r\n	<li>Peradeniya Botanical Garden</li>\r\n	<li>Madu River Boat Ride</li>\r\n	<li>Kosgoda Turtle Hatchery</li>\r\n</ul>\r\n\r\n<p><strong>Package Excludes:</strong></p>\r\n\r\n<ul>\r\n	<li>Sri Lankan entry visas</li>\r\n	<li>Early check in or late checkout</li>\r\n	<li>Lunch throughout the tour</li>\r\n	<li>Entrance Fees (Not mentioned Above)</li>\r\n	<li>Airfare</li>\r\n	<li>Optional tours and activities</li>\r\n	<li>Tips &amp; portage</li>\r\n	<li>Video/ Camera permit</li>\r\n	<li>All expenses of personal nature</li>\r\n</ul>',0,1,1,'2023-02-03 06:42:41','2025-11-24 15:54:38'),
(4,'Sharm El-Sheikh','Egypt',NULL,NULL,0,NULL,'Ray-Workman-92X132135362002','<p><strong>Discover the magic of Sharm El Sheikh with our limited time travel offer !</strong></p>\r\n\r\n<p><br />\r\nLet us craft the perfect getaway for you.<br />\r\nContact us for further information:<br />\r\ntours@worldwidetravel-lb.com<br />\r\n+961 1 366505<br />\r\n+961 79 119&nbsp;311</p>',0,1,1,'2023-02-03 14:32:24','2025-08-12 16:11:32'),
(5,'Hurghada','Egypt',NULL,'4 Days - 3 Nights',0,NULL,'Hurghada-3509565187M6494','<p>Elevate your Eid al-Fitr experience with our exclusive travel package to Hurghada.&nbsp;<br />\r\nOur full package ticket includes flights every Monday, Thursday and Sunday, 5-star hotel accommodations, and transfer insurance, so all you have to do is sit back, relax, and enjoy the beauty of Hurghada&#39;s crystal-clear waters.<br />\r\nBook now your tickets for just $600 per person!</p>',0,1,1,'2023-04-11 03:27:28','2024-09-19 05:24:36'),
(6,'Tenerife - Costa Adeje','Spain',NULL,'6 Days - 5 Nights',0,NULL,'Tenerife---Costa-Adeje-77848536859324V','<p>Experience the Ultimate Honeymoon in Paradise with our 5 Nights-6 Days Tenerife Honeymoon Package!<br />\r\nEscape to the stunning island of Tenerife&#39;s Costa Adeje, where you can relax and rejuvenate in the luxurious Iberostar BouganVille Playa hotel. This 5-night package is perfect for couples seeking a romantic and unforgettable getaway.<br />\r\n- Flight with MEA and private round-trip airport transfer to your hotel included<br />\r\n- Visit to the World Heritage Site of Mount Teide National Park for breathtaking natural wonders<br />\r\n- Stargazing excursion with a specialised guide and dinner<br />\r\n- 2-hour morning catamaran cruise to witness the beauty of dolphins in their natural habitat<br />\r\n- Package includes travel insurance and a 24-hour emergency telephone number for your safety and peace of mind<br />\r\n- All national taxes are also included in the package.<br />\r\nBook now and embark on a romantic journey with our Tenerife Honeymoon package. Make unforgettable memories that will last a lifetime!</p>',0,1,1,'2023-04-11 03:31:22','2024-09-19 06:31:50'),
(7,'Istanbul','Turkey',NULL,'4 Days - 3 Nights',0,NULL,'Istanbul-57051E104276219','<p>Discover the rich history and vibrant culture of Turkey, a land where the East meets the West.<br />\r\n&nbsp;</p>',0,1,1,'2023-04-11 03:56:20','2024-09-19 05:25:56'),
(8,'Beirut City Tour','Lebanon',NULL,NULL,0,NULL,'Beirut-City-Tour-37823923381328Q','<p>Welcome to our exciting tour of <strong>Beirut, Lebanon!</strong> We will take you on a journey through some of the most iconic landmarks in the city. Our tour includes a visit to the <strong>National Museum</strong>, where you can explore Lebanon&#39;s rich history through its vast collection of artifacts. <strong>Beirut Downtown</strong> is a bustling hub of activity, where you can enjoy the city&#39;s lively atmosphere with its numerous cafes, restaurants, and shops.<br />\r\n<br />\r\nNext, we&#39;ll head to <strong>Zaytouna Bay&#39;s Yacht Club</strong>, where you can unwind and take in the breathtaking views of the <strong>Mediterranean Sea</strong>. The tour also includes visits to two religious landmarks - the <strong>Mohamad Al Amin Mosque</strong> and the <strong>Saint George Church</strong> - both known for their unique architectural features and cultural significance.<br />\r\n<br />\r\nFinally, we will take you to witness the awe-inspiring natural beauty of <strong>Pigeon Rock</strong>, a towering natural wonder that stands tall at the entrance of Beirut&#39;s coast. Our tour promises to be an unforgettable experience, allowing you to discover the history, culture, and natural beauty of Beirut. Join us on this journey and create memories that will last a lifetime!</p>',0,1,1,'2023-04-19 09:14:36','2023-04-19 11:54:54'),
(9,'Beirut City and Chouf Mountains Tour','Lebanon',NULL,NULL,0,NULL,'Beirut-City-and-Chouf-Mountains-Tour-43813824281K788','<p>Welcome to our exclusive tour of <strong>Lebanon&#39;s iconic landmarks</strong>! We begin our journey with a visit to the<strong> National Museum</strong>, where you can explore Lebanon&#39;s rich history through its vast collection of artifacts. Beirut Downtown is our next stop, a bustling hub of activity where you can enjoy the city&#39;s lively atmosphere with its numerous cafes, restaurants, and shops.<br />\r\n<br />\r\nWe then head to <strong>Zaytouna Bay&#39;s Yacht Club</strong>, where you can unwind and take in the breathtaking views of the <strong>Mediterranean Sea</strong>. Our tour also includes visits to two religious landmarks - the <strong>Mohamad Al Amin Mosque</strong> and the <strong>Saint George Church</strong> - both known for their unique architectural features and cultural significance.<br />\r\n<br />\r\nOur journey takes us to the awe-inspiring natural beauty of <strong>Pigeon Rock</strong> before we head to the magnificent <strong>Beiteddine Palace</strong>, known for its intricate architecture and beautiful gardens. We also visit the historic <strong>Moussa Castle</strong>, which boasts a unique collection of armor and antique weapons.<br />\r\n<br />\r\nFinally, we explore the charming village of <strong>Deir el Qamar</strong>, known for its beautiful architecture, quaint streets, and stunning mountain views. Our tour promises to be an unforgettable experience, allowing you to discover the history, culture, and natural beauty of Lebanon. Join us on this journey and create memories that will last a lifetime!</p>',0,1,1,'2023-04-19 09:21:29','2023-04-19 11:54:44'),
(10,'Jeita - Harissa - Byblos Tour','Lebanon',NULL,NULL,0,NULL,'Jeita---Harissa---Byblos-Tour-67254564U798651','<p>Welcome to our exciting tour of Lebanon&#39;s most popular attractions! Our tour begins with a visit to the <strong>Jeita Grotto</strong>, a natural wonder that will leave you in awe of its stunning rock formations and underground lakes.<br />\r\n<br />\r\nWe then head to <strong>Harissa</strong> to visit the iconic statue of the <strong>Virgin Mary</strong>, which overlooks the <strong>Mediterranean Sea</strong>. You will also have the opportunity to take a <strong>cable car ride to Jounieh Bay</strong>, where you can enjoy the panoramic views of the coast.<br />\r\n<br />\r\nOur tour includes a visit to the charming <strong>old souks of Byblos</strong>, where you can explore the vibrant market and indulge in some shopping. We also take you to <strong>Byblos Castle</strong>, a historic landmark known for its unique architecture and rich history.<br />\r\n<br />\r\nJoin us on this journey of discovery and experience the best that <strong>Lebanon</strong> has to offer. Our tour promises to be an unforgettable experience, allowing you to explore the beauty, history, and culture of Lebanon. Don&#39;t miss out on this opportunity to create memories that will last a lifetime!</p>',0,1,1,'2023-04-19 09:25:08','2023-04-19 11:54:31'),
(11,'Baalbek - Anjar - Ksara Winery Tour','Lebanon',NULL,NULL,0,NULL,'Baalbek---Anjar---Ksara-Winery-Tour-3129120H4347289','<p>Welcome to our exclusive tour of Lebanon&#39;s iconic landmarks! Our journey begins with a visit to <strong>Baalbeck</strong>, home to some of the most magnificent Roman ruins in the world, including the <strong>Temple of Bacchus</strong> and the <strong>Temple of Jupiter</strong>.<br />\r\n<br />\r\nWe then head to the ancient <strong>city of Anjar</strong>, a UNESCO World Heritage site known for its unique blend of eastern and western architecture. You will have the opportunity to explore the city&#39;s well-preserved ruins and learn about its fascinating history.<br />\r\n<br />\r\nOur tour also includes a visit to the renowned <strong>Ksara Winery</strong>, where you can enjoy a cave tour and wine tasting. Learn about the history of wine production in <strong>Lebanon</strong> and sample some of the best wines the country has to offer.<br />\r\n<br />\r\nJoin us on this journey of discovery and experience the best that <strong>Lebanon</strong> has to offer. Our tour promises to be an unforgettable experience, allowing you to explore the history, culture, and natural beauty of <strong>Lebanon</strong>. Don&#39;t miss out on this opportunity to create memories that will last a lifetime!</p>',0,1,1,'2023-04-19 09:29:07','2023-04-19 11:54:10'),
(12,'Chouf Mountains Tour','Lebanon',NULL,NULL,0,NULL,'Chouf-Mountains-Tour-896874U94482280','<p>Welcome to our tour of the most enchanting landmarks in <strong>Lebanon</strong>! Our tour takes you on a journey of discovery, starting with a visit to the stunning <strong>Beiteddine Palace</strong>, an architectural marvel that showcases the grandeur and beauty of Lebanon&#39;s rich history.<br />\r\n<br />\r\nWe then head to the <strong>Moussa Castle</strong>, a unique landmark known for its medieval-style architecture and impressive collection of weapons and antiques. You will have the opportunity to explore the castle&#39;s various exhibitions and learn about the castle&#39;s history and its owner&#39;s legacy.<br />\r\n<br />\r\nOur tour also takes you to the charming village of <strong>Deir El Qamar</strong>, where you can stroll through the picturesque streets and soak up the authentic <strong>Lebanese</strong> atmosphere. You can also explore the town&#39;s historic landmarks, including its 16th-century mosque and the palace of <strong>Fakhreddine II</strong>.<br />\r\n<br />\r\nJoin us on this journey of discovery and experience the best that <strong>Lebanon</strong> has to offer. Our tour promises to be an unforgettable experience, allowing you to explore the history, culture, and natural beauty of <strong>Lebanon</strong>. Don&#39;t miss out on this opportunity to create memories that will last a lifetime!</p>',0,1,1,'2023-04-19 09:35:00','2023-04-19 11:53:58'),
(13,'Maghdouche - Sidon - Tyre Tour','Lebanon',NULL,NULL,0,NULL,'Maghdouche---Sidon---Tyre-Tour-99667832340146G','<p>Welcome to our tour of the beautiful cities of <strong>Tyre, Sidon, and Maghdouche</strong>! Our journey takes you on a historical and cultural adventure, starting with a visit to the ancient city of <strong>Tyre</strong>, known for its well-preserved <strong>Roman ruins</strong> and beautiful <strong>Mediterranean coastline</strong>.<br />\r\n<br />\r\nWe then head to the historic city of <strong>Sidon</strong>, where you can explore its charming souks and vibrant streets, filled with traditional shops, restaurants, and cafes. You can also visit the famous <strong>Sea Castle</strong>, an iconic landmark that has stood tall for centuries.<br />\r\n<br />\r\nOur tour also takes you to the picturesque town of <strong>Maghdouche</strong>, where you can visit the famous shrine of <strong>Our Lady of Mantara</strong> and soak up the peaceful atmosphere of this quaint town.<br />\r\n<br />\r\nWe then head back to <strong>Sidon</strong>, where you can continue your exploration of this ancient city and enjoy its many attractions before we return to <strong>Tyre</strong>.<br />\r\n<br />\r\nJoin us on this journey of discovery and experience the best that <strong>Lebanon</strong> has to offer. Our tour promises to be an unforgettable experience, allowing you to explore the history, culture, and natural beauty of <strong>Lebanon</strong>. Don&#39;t miss out on this opportunity to create memories that will last a lifetime!</p>',0,1,1,'2023-04-19 09:39:31','2023-04-19 11:53:46'),
(14,'Qadisha Valley - Cedars Tour','Lebanon',NULL,NULL,0,NULL,'Qadisha-Valley---Cedars-Tour-73651H244355907','<p>Embark on an unforgettable journey with us to explore the natural and cultural wonders of <strong>Lebanon</strong>. Our tour takes you through the magnificent <strong>Cedars Forest</strong>, where you can witness the awe-inspiring beauty of <strong>Lebanon&#39;s tallest trees</strong>.<br />\r\n<br />\r\nNext, we visit the<strong> Gibran Museum</strong>, a charming historic house that belonged to the renowned <strong>Lebanese writer and artist, Kahlil Gibran</strong>. The museum showcases his life and work and is set in a picturesque location overlooking the stunning <strong>Qadisha Valley</strong>.<br />\r\n<br />\r\nWe then head to the <strong>Qadisha Valley</strong>, a UNESCO World Heritage Site known for its rugged natural beauty and historical significance. Here, we visit the <strong>Qadisha Grotto</strong>, a natural wonder that boasts a stunning collection of stalactites and stalagmites.<br />\r\n<br />\r\nJoin us on this tour of Lebanon&#39;s natural and cultural treasures, where you can immerse yourself in the history, beauty, and culture of this breathtaking country. Our experienced guides will ensure that you have an unforgettable experience, filled with memories that will last a lifetime.</p>',0,1,1,'2023-04-19 09:43:49','2025-11-24 15:57:13'),
(15,'Tripoli - Batroun Tour','Lebanon',NULL,NULL,0,NULL,'Tripoli---Batroun-Tour-14816W398843233','<p>Join us on a journey to explore the rich history and culture of Lebanon&#39;s northern coast. Our tour takes you to the ancient city of <strong>Tripoli</strong>, where you can visit the majestic <strong>Tripoli Castle</strong> and the vibrant <strong>Old Souks</strong>, filled with traditional shops and stalls selling everything from spices to jewelry.<br />\r\n<br />\r\nNext, we head to the charming town of <strong>Batroun</strong>, where you can marvel at the impressive <strong>Phoenician Wall</strong>, a testament to the town&#39;s ancient history. We then continue on to the picturesque <strong>Msaylha Castle</strong>, where you can enjoy stunning views of the surrounding landscape and learn about the castle&#39;s fascinating history.<br />\r\n<br />\r\nLet us take you on a journey through time and experience the beauty and culture of Lebanon&#39;s northern coast. Our knowledgeable guides will ensure that you have an unforgettable experience, filled with memories that will last a lifetime.</p>',0,1,1,'2023-04-19 09:48:42','2025-11-24 15:56:27'),
(16,'Futuroscope Package','France',NULL,'2 Days - 1 Night',0,NULL,'Futuroscope-Package-09598U630604031','<p><strong>Futuroscope</strong> is an exciting <strong>European theme park</strong> that offers an unparalleled experience for visitors.<br />\r\n<br />\r\nAs a <strong>family theme park</strong>, <strong>Futuroscope</strong> places a strong emphasis on technology and visual effects, including the use of 3D and 4D technologies. The Park also features an extensive playground for children, known as <strong>&quot;Futuropolis,&quot;</strong> where kids can play and explore to their heart&#39;s content.<br />\r\n<br />\r\nTo make the most of your visit to <strong>Futuroscope</strong>, the park offers a 2-day and 1-night break that includes two consecutive day tickets with admission to the evening show, as well as one night with breakfast included.<br />\r\n<br />\r\nYou can choose to stay at one of three hotels, with prices starting from:<br />\r\n&nbsp;</p>\r\n\r\n<ul>\r\n	<li>Starting $180 for two adults and $90 for a child in a 2-star hotel</li>\r\n	<li>Starting $195 for two adults and $90 for a child in a 3-star hotel</li>\r\n	<li>Starting $210 for two adults and $90 for a child in a 4-star hotel.<br />\r\n	&nbsp;</li>\r\n</ul>\r\n\r\n<p>Book your tickets and hotel now to embark on a journey that you&#39;ll never forget!</p>\r\n\r\n<p>&nbsp;</p>',0,1,1,'2023-05-11 04:33:17','2024-09-19 06:32:12'),
