INSERT INTO `reviews` VALUES
(1,'Samer Dassouki','Regional Finance Director MEA','<p>Worldwide Travel &amp; Tourism provide us with valuable, reliable, and accurate service and are professional. Morover, teir team is courteous and helpful; always ready to provide assistance within and outside regular working hours.</p>\r\n\r\n<p>Based on our positive experience with Worldwide Travel &amp; Tourism, it is our pleasure to recommed their services.</p>',11,1,'2023-02-15 07:44:35','2025-03-27 09:54:35'),
(2,'Shady Hawwa','Vice président of distribution and DEM','<p>On the behalf of Haemonetics would like to recommend World Wide Travel which has been hired to manage all the logistics of our yearly event Regional Sales Distributor Meeting &quot;RSOM 2015&quot; in Muscat Oman.<br />\r\nWorld Wide Travel team has proven to be professional, experienced and knowledgeable they also made sure to provide us with the best service possible during this event.<br />\r\nWe look forward to team up with World Wide Travel team in future events.</p>',7,1,'2023-02-15 08:03:29','2025-03-27 09:53:45'),
(3,'Shaden Orfali','Conventions & Event Supervisor at Medtronic Mediterranean','<p>I would like to thank you for making this year&#39;s SH MENA Ditribution Meeting a total Success. Your proffesionalism and proactivity were the major contributors to the seamless execution of this event. The positive feedback we got from our guests says it all... we are proud to have you ar our partner and looking forward for future cooperation.</p>',4,1,'2023-02-15 09:03:11','2025-11-24 15:36:09'),
(4,'UNWOMEN ROAS Cairo','Regional Operations Manager','<p>We have worked with many travel agents over the past several years, and Worldwide Travel and Tourism stands head and sholders over trust over must, not only in demonstrated initiative, intelligence, and creativity, but also Worldwide Travel ability to function as a productive event organizer.</p>',5,1,'2023-02-15 09:07:31','2025-03-27 09:48:49'),
(5,'Elie Kodsi','UNDP Lebanon Staff','<p>Excellent service like usual!&nbsp;<br />\r\nThe seating arrangement is perfect; my daughter will be very happy.&nbsp;<br />\r\nThis is the first time that we reserve seats with Air Canada without paying for them - much appreciated.</p>',6,1,'2023-04-27 09:22:36','2025-03-27 09:48:52'),
(6,'Guy Najm','Boston Scientific','<p>Amazing collaboration and follow up Suzi and Zeinab. Lucky to have you Zeinab leading the biggest Endo MENA event in 2023!</p>',8,1,'2023-06-09 05:55:51','2025-03-27 09:50:50'),
(7,'UN Women','Regional Office for Arab States','<p>I would like to seize this opportunity to thank you and the WWTT team; especially Mirna for the professional support before and during the event. Much appreciated.</p>',9,1,'2023-06-23 08:50:35','2025-03-27 09:50:51'),
(8,'Leonardo Paradiso','UNODC','<p>Dear colleagues at WWTT, I cannot thank you enough for all you did for this project.<br />\r\nYou&#39;ve been really excellent, both from a professional and personal perspective. Bianca and I are at the airport and are grateful to all of you.</p>\r\n\r\n<p>With many thanks and much love to all,<br />\r\nLeonardo</p>',10,1,'2023-09-21 04:50:15','2025-03-27 09:50:53'),
(9,'Hayfa Koleilat','Head of Marketing – Emerging Markets & APAC  - Coloplast','<p><span style=\"font-size:11pt\"><span style=\"font-family:Aptos,sans-serif\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">I would like to take this opportunity to thank you for your support throughout our meetings.</span></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Aptos,sans-serif\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">Everything went smoothly and the level of responsiveness during the meeting was great.</span></span></span></span></p>\r\n\r\n<p>&nbsp;</p>',1,1,'2025-03-27 09:40:20','2025-03-27 09:48:55'),
(10,'Seyma Yavuz','Principal Tradeshows and Events for GEM region','<p><span style=\"font-size:11pt\"><span style=\"font-family:Aptos,sans-serif\">I should have thank you so much, for your cooperation, always smiling and eager to help. And all your support.</span></span></p>',3,1,'2025-03-27 09:47:23','2025-03-27 09:53:47'),
(11,'Raouia Zaanouni','Communications Analyst','<p>I would like to take a moment to express my heartfelt thanks to you and your team for the incredible work and support provided for our event at La Menara Hotel. Everything went perfectly, and we are truly grateful for the professionalism, patience, and attention to detail the team demonstrated throughout the process.</p>\r\n\r\n<p>It was an absolute pleasure collaborating with you, and I look forward to future opportunities to work together. Please extend our gratitude to everyone involved.</p>',2,1,'2025-03-27 09:54:33','2025-11-05 09:53:10'),
(12,'Mohamad Yamout','(Marketing Manager, Middle East & North Africa Urology – Boston Scientific)','<p>I wanted to take a moment to express my heartfelt appreciation for the outstanding service you provided during our workshop in Amsterdam . Your attention to detail in handling all travel arrangements and the warm welcome of our guests played a great role in the success of the event.</p>\r\n\r\n<p>Your team&rsquo;s professionalism is highly noticed, and we truly appreciate the effort put into ensuring everything ran smoothly. From the seamless coordination of travel logistics (Zeinab &amp; Sawsan) to the welcoming atmosphere you created for our guests (Sara) , every aspect contributed to a memorable experience.</p>\r\n\r\n<p>Thank you once again for your hard work and commitment. We look forward to collaborating with you again in the future.<br />\r\n&nbsp;</p>',NULL,1,'2025-08-20 18:12:14','2025-08-20 18:43:15'),
(13,'Thuraya Ahmad Ismail','Board Member and CEO at Mentor Arabia','<p>We are honored to have Worldwide Travel and Tourism as a valued strategic partner, and look forward to collaborating on future initiatives that drive meaningful change and brighter future for our youth. Together, we can make a tangible difference in the lives of young people across the region towards sustainably developed societies.<br />\r\n&nbsp;</p>',NULL,1,'2025-10-13 08:15:54','2025-10-13 08:16:35'),
(14,'Mohamad Yamout','Marketing Manager, Middle East & North Africa Urology - Boston Scientific','<p>I wanted to take a moment to express my sincere gratitude for the exceptional job you did in managing Madrid Workshop.<br />\r\nEverything went smoothly, and the positive feedback from participants has been great too. Your ability to handle challenges and coordinate all aspects of the event was impressive and greatly appreciated</p>',NULL,1,'2025-10-13 08:17:01','2025-10-13 08:17:27'),
(15,'Dyala Daood','Administrative Assistant at MEALIS GROUP','<p>I just wanted to share with you that our team gave very positive feedback about the hotel, the setup, the dinner, the coffee, and the overall organization.</p>\r\n\r\n<p><br />\r\nWe appreciate your efforts and would like to thank you and the hotel management.</p>\r\n\r\n<p>&nbsp;</p>',NULL,1,'2025-10-16 22:58:05','2025-11-05 09:52:33'),
(16,'Basia starzyńska','Business Support Partner GEM Business Assistant - Boston Scientific','<p>I wanted to take a moment to express my sincere gratitude for all your help and dedication in organizing our recent arrangements for the Dubai event. Your responsiveness, attention to detail, and proactive approach made a significant difference in ensuring everything ran smoothly. (And I know it was A LOT!)<br />\r\nFrom clarifying details to securing bookings and promptly sharing proposals, you consistently went above and beyond. Your professionalism and willingness to accommodate last-minute (even the big ones!) requests did not go unnoticed and truly reflect exceptional service.<br />\r\nIt has been a pleasure working with Yasmine, and I deeply appreciate the effort you put into making this a success. Thank you once again for your outstanding support&mdash;I look forward to collaborating with you on future projects!</p>\r\n\r\n<p>&nbsp;</p>',NULL,1,'2025-11-12 10:09:49','2025-12-01 09:37:12');
INSERT INTO `services` VALUES
(4,'Visa Processing','<ul style=\"list-style-type:disc\">\r\n	<li>Visa consultant team is available 7 days a week, updated with most worldwide visas rules and regulations.</li>\r\n	<li>Submit worldwide visas with all needed documents with translation services.</li>\r\n</ul>',NULL,NULL,NULL,1,'2023-01-24 11:22:44','2023-10-09 07:09:12'),
(5,'Transportation & Logistical Assistance','<ul style=\"list-style-type:disc\">\r\n	<li>Transference, buses, trains, limousine, and internal flights.</li>\r\n	<li>Pledge that the drivers follow the ethical standards and have the professional behavior.</li>\r\n	<li>Provide car with clean, no smoking smells with seat belts and be maintained on timely basis.</li>\r\n	<li>Make the necessary confirmation on the airport transport service by the transport supervisor 24 hours in advance.</li>\r\n	<li>Shipping services.</li>\r\n</ul>',NULL,NULL,NULL,1,'2023-01-24 11:22:58','2023-10-09 07:08:28'),
(6,'Travel Insurance','<p>Flexible International Travel Insurance policies covering all nationalities, travelling almost anywhere in the world. You can purchase travel insurance for a specific single trip or, for total flexibility, an annual policy that covers you for any trip you take abroad, regardless of how often you travel.</p>',NULL,NULL,NULL,1,'2023-01-24 11:23:28','2023-04-12 05:55:00'),
(7,'Sports Ticketing','<p>Get ready for an amazing journey with us!</p>\r\n\r\n<p>We bring together the fun of travel with the thrill of live sports. Cheering for your favorite team in a football match, enjoying a basketball game, or experiencing the high-speed excitement of Formula One , we&#39;ve got exclusive tickets for it all! Let us be your guide to unforgettable moments, blending the joy of travel with the excitement of sports. Join us for an adventure that combines the love of travel with the thrill of live sports, making memories that will last a lifetime!</p>',NULL,NULL,NULL,1,'2023-10-09 07:28:47','2024-01-19 12:49:36');
